const table=layui.table,util=layui.util;table.render({elem:"#sort",url:"/api/sort/list",page:!0,cols:[[{field:"sortId",title:"ID",width:100},{field:"content",title:"分类"},{title:"文章数量",templet:({articles:articles})=>articles.length},{title:"创建者",templet:({user:user})=>user.nickName},{title:"创建时间",templet:({createdAt:createdAt})=>util.toDateString(createdAt,"yyyy-MM-dd HH:mm:ss")}]]});